create type public.short_drama_status as enum ('draft','generating','completed','failed');
create table public.short_drama_assets(id uuid primary key default gen_random_uuid(),user_id uuid references public.profiles(id) on delete set null,task_id uuid unique references public.content_tasks(id) on delete cascade,title text,status public.short_drama_status not null default 'generating',story jsonb,characters jsonb,scenes jsonb,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table public.short_drama_scenes(id uuid primary key default gen_random_uuid(),drama_id uuid not null references public.short_drama_assets(id) on delete cascade,scene_number integer not null,content jsonb not null default '{}'::jsonb,image_task_id uuid references public.image_tasks(id) on delete set null,video_task_id uuid references public.video_tasks(id) on delete set null,status public.task_status not null default 'pending',unique(drama_id,scene_number));
alter table public.short_drama_assets enable row level security; alter table public.short_drama_scenes enable row level security;
create policy "drama assets own" on public.short_drama_assets for select using(user_id=auth.uid() or public.is_admin());
